import { Component, h, Prop, Element } from '@stencil/core';
import { customTwMerge } from '../../utils/utils';

export type IconSize = 'xxsmall' | 'xsmall' | 'small' | 'medium' | 'medium-alt' | 'large' | 'xlarge';
export type IconBackground = 'none' | 'circle' | 'square';
export type IconVariant = 'primary' | 'secondary' | 'success' | 'warning' | 'error' | 'info' | 'neutral';

interface VariantConfig {
  bg: string;
  color: string;
  hover?: string;
}

@Component({
  tag: 'wdpr-icon',
  shadow: true,
  styles: `
    :host {
      display: flex;
      align-items: center;
      justify-content: center;
    }
  `,
})
export class WdprIcon {
  @Element() el: HTMLElement;

  @Prop() icon: string;
  @Prop() size: IconSize = 'medium';
  @Prop() background: IconBackground = 'none';
  @Prop() variant: IconVariant = 'primary';
  @Prop() iconTitle?: string;
  @Prop() iconDescription?: string;
  @Prop() customClass?: string;
  @Prop() decorative: boolean = false;
  @Prop({ attribute: 'a11y-label' }) a11yLabel?: string;

  // Size configuration using Record
  private readonly sizeConfig: Record<IconSize, string> = {
    'xxsmall': 'p-087',
    'xsmall': 'p-125',
    'small': 'p-125',
    'medium': 'p-125',
    'medium-alt': 'p-200',
    'large': 'p-200',
    'xlarge': 'p-250',
  };

  // Variant configuration for icons without background
  private readonly variantColorsOnly: Record<IconVariant, string> = {
    primary: 'text-surface-actionable-default',
    secondary: 'text-text-neutral-default',
    success: 'text-surface-status-success',
    warning: 'text-surface-status-warning',
    error: 'text-surface-status-critical',
    info: 'text-surface-status-informational',
    neutral: 'text-neutral-dark',
  };

  // Variant configuration for icons with background
  private readonly variantWithBackground: Record<IconVariant, VariantConfig> = {
    primary: {
      bg: 'bg-surface-actionable-default',
      color: 'text-white',
    },
    secondary: {
      bg: 'bg-component-icon',
      color: 'text-text-neutral-dark',
    },
    success: {
      bg: 'bg-surface-status-success-alt',
      color: 'text-text-status-success',
    },
    warning: {
      bg: 'bg-surface-status-warning-alt',
      color: 'text-text-status-warning',
    },
    error: {
      bg: 'bg-surface-status-critical-alt',
      color: 'text-text-status-critical',
    },
    info: {
      bg: 'bg-surface-status-informational-alt',
      color: 'text-text-status-informational',
    },
    neutral: {
      bg: 'bg-surface-neutral-medium',
      color: 'text-neutral-extra-dark',
    },
  };

  // Background shape configuration
  private readonly backgroundShapes: Record<IconBackground, string> = {
    none: '',
    circle: 'rounded-pill',
    square: '', // Dynamic based on size
  };

  // Square border radius by size
  private readonly squareBorderRadius: Record<IconSize, string> = {
    'xxsmall': 'rounded-050',
    'xsmall': 'rounded-100',
    'small': 'rounded-100',
    'medium': 'rounded-100',
    'medium-alt': 'rounded-150',
    'large': 'rounded-150',
    'xlarge': 'rounded-150',
  };

  private getSizeClasses(): string {
    if (this.size === 'xlarge' && this.background === 'circle') return 'p-200';

    return this.sizeConfig[this.size as Exclude<IconSize, 'xlarge'>];
  }

  private getVariantClasses(): VariantConfig {
    if (this.background === 'none') {
      return {
        bg: '',
        color: this.variantColorsOnly[this.variant],
      };
    }

    return this.variantWithBackground[this.variant];
  }

  private getContainerClasses(): string {
    const sizeClasses = this.getSizeClasses();
    const variantClasses = this.getVariantClasses();
    const backgroundShape = this.backgroundShapes[this.background];
    const squareRadius = this.background === 'square' ? this.squareBorderRadius[this.size] : '';

    const baseClasses = 'inline-flex items-center justify-center relative transition-all duration-100';

    return customTwMerge(baseClasses, sizeClasses, variantClasses.bg, variantClasses.color, backgroundShape, squareRadius, this.customClass || '');
  }

  render() {
    return (
      <wdpr-surface-style variant="none" padding="none">
        <div class={this.getContainerClasses()}>
          <wdpr-icon-library
            icon={this.icon}
            size={this.size}
            ariaTitle={this.iconTitle}
            ariaDescription={this.iconDescription}
            a11yLabel={this.a11yLabel}
            decorative={this.decorative}
          />
          {this.iconDescription && <span class="sr-only">{this.iconDescription}</span>}
        </div>
      </wdpr-surface-style>
    );
  }
}
